```typescript
export type SummitAttemptState =
  | { status: "none" }
  | { status: "climbing"; id: string; peak: string; checkpoints: number }
  | { status: "summited"; id: string; summitedAt: string }
  | { status: "aborted"; id: string; reason: string };

export type SummitAttemptCommand =
  | { type: "start"; id: string; peak: string }
  | { type: "reachCheckpoint"; name: string }
  | { type: "reachSummit"; at: string }
  | { type: "abort"; reason: string };

export type SummitAttemptEvent =
  | { type: "SummitAttemptStarted"; id: string; peak: string }
  | { type: "CheckpointReached"; name: string }
  | { type: "SummitReached"; at: string }
  | { type: "Aborted"; reason: string };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const summitAttemptDecider: Decider<SummitAttemptCommand, SummitAttemptEvent, SummitAttemptState> = {
  initialState: { status: "none" },
  decide(command, state) {
    if (state.status === "aborted") throw new DomainError("ABORTED");
    switch (command.type) {
      case "start":
        if (state.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "SummitAttemptStarted", id: command.id, peak: command.peak }];
      case "reachCheckpoint":
        if (state.status !== "climbing") throw new DomainError("NOT_CLIMBING");
        return [{ type: "CheckpointReached", name: command.name }];
      case "reachSummit":
        if (state.status !== "climbing") throw new DomainError("NOT_CLIMBING");
        return [{ type: "SummitReached", at: command.at }];
      case "abort":
        if (state.status !== "climbing") throw new DomainError("NOT_CLIMBING");
        return [{ type: "Aborted", reason: command.reason }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN_COMMAND");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "SummitAttemptStarted":
        return { status: "climbing", id: event.id, peak: event.peak, checkpoints: 0 };
      case "CheckpointReached":
        if (state.status !== "climbing") return state;
        return { ...state, checkpoints: state.checkpoints + 1 };
      case "SummitReached":
        if (state.status !== "climbing") return state;
        return { status: "summited", id: state.id, summitedAt: event.at };
      case "Aborted":
        if (state.status !== "climbing") return state;
        return { status: "aborted", id: state.id, reason: event.reason };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
