```typescript
export type AcclimatisationEvent =
  | { type: "AcclimatisationBegun"; climberId: string; climberName: string; startedAt: string }
  | { type: "RotationCompleted"; altitude: number; at: string }
  | { type: "RestDayLogged"; at: string }
  | { type: "AcclimatisationCleared"; clearedAt: string };

export interface AcclimatisationView {
  readonly climberId: string;
  readonly climberName: string;
  readonly rotations: number;
  readonly highestAltitude: number;
  readonly lastActivityAt: string;
  readonly cleared: boolean;
}

export const emptyView: AcclimatisationView = {
  climberId: "",
  climberName: "",
  rotations: 0,
  highestAltitude: 0,
  lastActivityAt: "",
  cleared: false,
};

export function project(view: AcclimatisationView, event: AcclimatisationEvent): AcclimatisationView {
  switch (event.type) {
    case "AcclimatisationBegun":
      return {
        climberId: event.climberId,
        climberName: event.climberName,
        rotations: 0,
        highestAltitude: 0,
        lastActivityAt: event.startedAt,
        cleared: false,
      };
    case "RotationCompleted":
      return {
        ...view,
        rotations: view.rotations + 1,
        highestAltitude: Math.max(view.highestAltitude, event.altitude),
        lastActivityAt: event.at,
      };
    case "RestDayLogged":
      return { ...view, lastActivityAt: event.at };
    case "AcclimatisationCleared":
      return { ...view, lastActivityAt: event.clearedAt, cleared: true };
    default: {
      const _never: never = event;
      return view;
    }
  }
}

export function projectAll(events: AcclimatisationEvent[]): AcclimatisationView {
  return events.reduce(project, emptyView);
}
