export type RouteRecceEvent =
  | { type: "RecceStarted"; recceId: string; by: string }
  | { type: "MarkerPlanted"; name: string; lat: number; lon: number }
  | { type: "HazardSpotted"; kind: string; severity: number }
  | { type: "RecceClosed"; at: string };

export interface RouteRecceView {
  readonly markers: ReadonlyArray<{ name: string; lat: number; lon: number }>;
  readonly hazardCount: number;
  readonly maxSeverity: number;
}

export const emptyView: RouteRecceView = {
  markers: [],
  hazardCount: 0,
  maxSeverity: 0,
};

export function project(view: RouteRecceView, event: RouteRecceEvent): RouteRecceView {
  switch (event.type) {
    case "MarkerPlanted":
      return {
        ...view,
        markers: [...view.markers, { name: event.name, lat: event.lat, lon: event.lon }],
      };
    case "HazardSpotted":
      return {
        ...view,
        hazardCount: view.hazardCount + 1,
        maxSeverity: Math.max(view.maxSeverity, event.severity),
      };
    case "RecceStarted":
    case "RecceClosed":
      return view;
    default: {
      const _never: never = event;
      return view;
    }
  }
}
