```typescript
export type ExpeditionEvent =
  | { type: "ExpeditionPlanned"; id: string; peak: string }
  | { type: "MemberEnrolled" }
  | { type: "ExpeditionLaunched"; at: string };

export interface ExpeditionView {
  readonly id: string;
  readonly peak: string;
  readonly launched: boolean;
  readonly memberCount: number;
}

export const emptyView: ExpeditionView = {
  id: "",
  peak: "",
  launched: false,
  memberCount: 0,
};

export function project(view: ExpeditionView, event: ExpeditionEvent): ExpeditionView {
  switch (event.type) {
    case "ExpeditionPlanned":
      return { id: event.id, peak: event.peak, launched: false, memberCount: 0 };
    case "MemberEnrolled":
      return { ...view, memberCount: view.memberCount + 1 };
    case "ExpeditionLaunched":
      return { ...view, launched: true };
    default: {
      const _never: never = event;
      return view;
    }
  }
}

export function projection(events: ExpeditionEvent[]): ExpeditionView {
  return events.reduce(project, emptyView);
}
```

A projection fans out a stream of domain events into a shape optimised for reads, not for writing. It is append-only: the projection function folds each event into the view, and the view's type is denormalised — flat fields, indexable identifiers, precomputed counts. evolve, by contrast, rebuilds an aggregate's internal state so decide can protect its invariants. The two share the event union but live on opposite sides of the CQRS boundary, and a single stream can feed many projections.

```typescript
export type WeatherWindowEvent =
  | { type: "WindowForecast"; windowId: string; from: string; to: string; quality: number }
  | { type: "WindowOpened"; windowId: string; at: string }
  | { type: "WindowClosed"; windowId: string; at: string };

export interface WindowRow {
  readonly windowId: string;
  readonly from: string;
  readonly to: string;
  readonly quality: number;
  readonly open: boolean;
}

export interface WeatherWindowView {
  readonly windows: ReadonlyArray<WindowRow>;
}

export const emptyView: WeatherWindowView = { windows: [] };

export function project(view: WeatherWindowView, event: WeatherWindowEvent): WeatherWindowView {
  switch (event.type) {
    case "WindowForecast": {
      const row: WindowRow = {
        windowId: event.windowId,
        from: event.from,
        to: event.to,
        quality: event.quality,
        open: false,
      };
      return { windows: [...view.windows, row] };
    }
    case "WindowOpened":
      return {
        windows: view.windows.map((w) => (w.windowId === event.windowId ? { ...w, open: true } : w)),
      };
    case "WindowClosed":
      return {
        windows: view.windows.map((w) => (w.windowId === event.windowId ? { ...w, open: false } : w)),
      };
    default: {
      const _never: never = event;
      return view;
    }
  }
}
