```typescript
export interface BaseCampV1 {
  readonly id: string;
  readonly altitude: number;
  readonly occupants: number;
}

export interface BaseCampV2 {
  readonly id: string;
  readonly altitude: number;
  readonly occupants: number;
  readonly pitchedAt: string;
}

export interface BaseCampV3 {
  readonly id: string;
  readonly altitude: number;
  readonly occupants: number;
  readonly pitchedAt: string;
  readonly regionCode: string;
}

export type CurrentBaseCamp = BaseCampV3;

export const CURRENT_VERSION = 3 as const;

export interface Snapshot<S> {
  readonly version: number;
  readonly state: S;
}

export function v1Tov2(v1: BaseCampV1): BaseCampV2 {
  return { ...v1, pitchedAt: "1970-01-01T00:00:00Z" };
}

export function v2Tov3(v2: BaseCampV2): BaseCampV3 {
  return { ...v2, regionCode: "UNKNOWN" };
}

export class UnknownSnapshotVersion extends Error {
  constructor(version: number) {
    super(`unknown snapshot version ${version}`);
    this.name = "UnknownSnapshotVersion";
  }
}

export function loadSnapshot(raw: Snapshot<unknown>): Snapshot<CurrentBaseCamp> {
  let version = raw.version;
  let state: unknown = raw.state;
  while (version < CURRENT_VERSION) {
    if (version === 1) {
      state = v1Tov2(state as BaseCampV1);
      version = 2;
    } else if (version === 2) {
      state = v2Tov3(state as BaseCampV2);
      version = 3;
    } else {
      throw new UnknownSnapshotVersion(version);
    }
  }
  if (version !== CURRENT_VERSION) throw new UnknownSnapshotVersion(version);
  return { version: CURRENT_VERSION, state: state as CurrentBaseCamp };
}
