export interface SummitAttemptState {
  readonly id: string;
  readonly peak: string;
  readonly checkpoints: number;
  readonly status: "climbing" | "summited" | "aborted";
}

export interface Snapshot<S> {
  readonly version: number;
  readonly revision: bigint;
  readonly state: S;
}

export const CURRENT_SNAPSHOT_VERSION = 1 as const;
export const SNAPSHOT_EVERY_N_EVENTS = 50n;

export function shouldSnapshot(
  streamRevision: bigint,
  lastSnapshot: Snapshot<SummitAttemptState> | null,
): boolean {
  const last = lastSnapshot === null ? -1n : lastSnapshot.revision;
  return streamRevision - last >= SNAPSHOT_EVERY_N_EVENTS;
}

export function buildSnapshot(
  state: SummitAttemptState,
  revision: bigint,
): Snapshot<SummitAttemptState> {
  return { version: CURRENT_SNAPSHOT_VERSION, revision, state };
}

export function isCurrentSnapshot(
  snap: Snapshot<SummitAttemptState>,
): boolean {
  return snap.version === CURRENT_SNAPSHOT_VERSION;
}
