  readSnapshot(stream: string): Promise<Snapshot<GearCheckState> | null>;
  readStream(stream: string, fromRevision: bigint): Promise<{ events: ReadonlyArray<E>; lastRevision: bigint }>;
}

export const initialState: GearCheckState = { id: "", items: 0, failed: 0, signedOff: false };

export function evolve(state: GearCheckState, event: GearCheckEvent): GearCheckState {
  switch (event.type) {
    case "GearCheckBegun":
      return { id: event.id, items: 0, failed: 0, signedOff: false };
    case "ItemInspected":
      return { ...state, items: state.items + 1, failed: state.failed + (event.passed ? 0 : 1) };
    case "GearCheckSignedOff":
      return { ...state, signedOff: true };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export async function loadFromSnapshot(
  store: EventStore<GearCheckEvent>,
  streamName: string,
): Promise<{ state: GearCheckState; revision: bigint }> {
  const snap = await store.readSnapshot(streamName);
  const from = snap === null ? 0n : snap.revision + 1n;
  const seed = snap === null ? initialState : snap.state;
  const tail = await store.readStream(streamName, from);
  let state = seed;
  for (const event of tail.events) {
    state = evolve(state, event);
  }
  return { state, revision: tail.lastRevision };
}
