  | { type: "plan"; id: string; peak: string }
  | { type: "launch"; at: string };

export type ExpeditionEvent =
  | { type: "ExpeditionPlanned"; id: string; peak: string }
  | { type: "ExpeditionLaunched"; at: string };

export const initialState: ExpeditionState = { status: "none" };

export function evolve(state: ExpeditionState, event: ExpeditionEvent): ExpeditionState {
  switch (event.type) {
    case "ExpeditionPlanned":
      return { status: "planned", id: event.id, peak: event.peak };
    case "ExpeditionLaunched":
      if (state.status !== "planned") return state;
      return { status: "launched", id: state.id, peak: state.peak, launchedAt: event.at };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export function decide(command: ExpeditionCommand, state: ExpeditionState): ExpeditionEvent[] {
  switch (command.type) {
    case "plan":
      if (state.status !== "none") throw new Error("EXISTS");
      return [{ type: "ExpeditionPlanned", id: command.id, peak: command.peak }];
    case "launch":
      if (state.status !== "planned") throw new Error("NOT_PLANNED");
      return [{ type: "ExpeditionLaunched", at: command.at }];
    default: {
      const _never: never = command;
      throw new Error("UNKNOWN_COMMAND");
    }
  }
}

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore<E> {
  readStream(stream: string): Promise<{ events: ReadonlyArray<E>; revision: ExpectedRevision }>;
  appendToStream(
    stream: string,
    events: ReadonlyArray<E>,
    opts: { expectedRevision: ExpectedRevision },
  ): Promise<bigint>;
}

export function handleExpedition(
  store: EventStore<ExpeditionEvent>,
  streamName: string,
  command: ExpeditionCommand,
): Effect.Effect<void, Error> {
  return Effect.gen(function* () {
    const loaded = yield* Effect.promise(() => store.readStream(streamName));
    let state = initialState;
    for (const event of loaded.events) {
      state = evolve(state, event);
    }
    const events = decide(command, state);
    yield* Effect.promise(() =>
      store.appendToStream(streamName, events, { expectedRevision: loaded.revision }),
    );
  });
}
