export function evolve(state: SummitAttemptState, event: SummitAttemptEvent): SummitAttemptState {
  switch (event.type) {
    case "SummitAttemptStarted":
      return { keys: new Set([...state.keys, event.idempotencyKey]), started: true };
    case "CheckpointReached":
      return { keys: new Set([...state.keys, event.idempotencyKey]), started: state.started };
