  if (state.keys.has(command.idempotencyKey)) return [];
  if (state.started) throw new Error("ALREADY_STARTED");
  return [
    {
      type: "SummitAttemptStarted",
      id: command.id,
      peak: command.peak,
      idempotencyKey: command.idempotencyKey,
    },
  ];
