  switch (command.type) {
    case "begin":
      if (state.status !== "none") throw new Error("EXISTS");
      return [{ type: "GearCheckBegun", id: command.id }];
    case "inspectItem":
      if (state.status !== "inProgress") throw new Error("NOT_IN_PROGRESS");
      return [{ type: "ItemInspected", passed: command.passed }];
    default: {
      const _never: never = command;
      throw new Error("UNKNOWN_COMMAND");
    }
  }
