  let view = await readModel.load();
  const readStream = async (): Promise<void> => {
    for await (const envelope of source) {
      if (start !== null && envelope.position <= start) continue;
      view = await readModel.apply(view, envelope.event);
      await readModel.save(view);
      await checkpointStore.write(name, envelope.position);
