    case "CheckpointReached":
      return { ...state, checkpoints: state.checkpoints + 1 };
    case "SummitReached":
      return { ...state, status: "summited" };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  whenFn: (state: S, event: E) => S,
  initial: S,
): Promise<S> {
  let state = initial;
  const consume = async (): Promise<void> => {
    for await (const event of stream) {
      state = whenFn(state, event);
    }
  };
  await consume();
  return state;
}

export async function loadSummitAttempt(
  stream: AsyncIterable<SummitAttemptEvent>,
): Promise<SummitAttemptState> {
  return aggregateStream(stream, when, initialState);
}
```

A generic aggregateStream<S, E> decouples the folding machinery from any particular aggregate, so every event-sourced type gets the same loader for free. The function accepts an AsyncIterable<E> so the caller can pipe an event-store cursor straight in; it folds with a pure when(state, event) and returns the final state. Keeping the signature parametric is what makes the helper reusable — GearCheck, Expedition, Sherpa all share the same code path and only supply their own evolve and initial state.

```typescript
export type GearCheckEvent =
  | { type: "GearCheckBegun"; id: string }
  | { type: "ItemInspected"; passed: boolean }
  | { type: "GearCheckSignedOff"; at: string };

export interface GearCheckState {
  readonly id: string;
  readonly items: number;
  readonly failed: number;
  readonly signedOff: boolean;
}

export const initialState: GearCheckState = { id: "", items: 0, failed: 0, signedOff: false };

export function when(state: GearCheckState, event: GearCheckEvent): GearCheckState {
  switch (event.type) {
    case "GearCheckBegun":
      return { id: event.id, items: 0, failed: 0, signedOff: false };
    case "ItemInspected":
      return { ...state, items: state.items + 1, failed: state.failed + (event.passed ? 0 : 1) };
    case "GearCheckSignedOff":
      return { ...state, signedOff: true };
    default: {
      const _never: never = event;
      return state;
    }
  }
}

export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  whenFn: (state: S, event: E) => S,
  initial: S,
): Promise<S> {
  let state = initial;
  const loop = async (): Promise<void> => {
    for await (const event of stream) {
      state = whenFn(state, event);
    }
  };
  await loop();
  return state;
}
