    case "SherpaAssigned":
      return { type: "SherpaAssigned", expeditionId: raw.data.expeditionId };
    default: {
      const _never: never = raw;
      throw new UnknownEventError("unknown", 0);
    }
  }
}

export function evolve(events: ReadonlyArray<RawSherpaEvent>): SherpaEvent[] {
  return events.map(upcast);
