export type RescueOperationEvent =
  | { type: "RescueRequested"; id: string; peak: string }
  | { type: "RescuerDispatched"; rescuerId: string }
  | { type: "RescueConcluded"; at: string };

export interface RescueView {
  readonly id: string;
  readonly rescuers: number;
  readonly status: "requested" | "concluded";
}

export const emptyView: RescueView = { id: "", rescuers: 0, status: "requested" };

export function project(view: RescueView, event: RescueOperationEvent): RescueView {
  switch (event.type) {
    case "RescueRequested":
      return { id: event.id, rescuers: 0, status: "requested" };
    case "RescuerDispatched":
      return { ...view, rescuers: view.rescuers + 1 };
    case "RescueConcluded":
      return { ...view, status: "concluded" };
    default: {
      const _never: never = event;
      return view;
    }
  }
}

export interface EventBatch<E> {
  readonly events: ReadonlyArray<E>;
  readonly nextRevision: bigint;
}

export interface EventStore<E> {
  readStream(from: bigint, batchSize: number): Promise<EventBatch<E>>;
}

export interface Reporter {
  report(revision: bigint, count: number): void;
}

export async function rebuild(
  store: EventStore<RescueOperationEvent>,
  persist: (view: RescueView) => Promise<void>,
  reporter: Reporter,
  from: bigint = 0n,
  batchSize: number = 500,
): Promise<void> {
  let cursor = from;
  let view = emptyView;
  let total = 0;
  let done = false;
  while (!done) {
    const batch = await store.readStream(cursor, batchSize);
    if (batch.events.length === 0) {
      done = true;
      break;
    }
    for (const event of batch.events) {
      view = project(view, event);
      total += 1;
    }
    await persist(view);
    reporter.report(batch.nextRevision, total);
    cursor = batch.nextRevision;
  }
}
