Domain events describe local truth: fine-grained, mutable in shape over time, owned by one bounded context. Integration events are a public contract: coarser, versioned, and documented for external consumers. Mixing the two leaks internal invariants and couples outside systems to your refactors. A translate(domainEvent): IntegrationEvent | null keeps the mapping explicit — not every domain event crosses the boundary, and each integration event carries a schema tag so consumers can evolve independently.

```typescript
export type SherpaDomainEvent =
  | { type: "SherpaHired"; id: string; name: string }
  | { type: "SherpaAssigned"; expeditionId: string }
  | { type: "SherpaReleased" }
  | { type: "SherpaDischarged" };

export type IntegrationEvent =
  | {
      readonly schema: "sherpa.available.v1";
      readonly payload: { readonly sherpaId: string; readonly name: string };
    }
  | {
      readonly schema: "sherpa.discharged.v1";
      readonly payload: { readonly sherpaId: string };
    };

export interface SherpaIdentity {
  readonly sherpaId: string;
  readonly name: string;
}

export function translate(event: SherpaDomainEvent, identity: SherpaIdentity): IntegrationEvent | null {
  switch (event.type) {
    case "SherpaHired":
      return {
        schema: "sherpa.available.v1",
        payload: { sherpaId: event.id, name: event.name },
      };
    case "SherpaDischarged":
      return {
        schema: "sherpa.discharged.v1",
        payload: { sherpaId: identity.sherpaId },
      };
    case "SherpaAssigned":
    case "SherpaReleased":
      return null;
    default: {
      const _never: never = event;
      return null;
    }
  }
}

export interface EventStore<E> {
  appendToStream(stream: string, events: ReadonlyArray<E>): Promise<void>;
}
