export type BaseCampState =
  | { status: "none" }
  | { status: "pitched"; id: string; altitude: number };

export type BaseCampCommand =
  | { type: "pitch"; id: string; altitude: number }
  | { type: "strike"; at: string };

export type BaseCampEvent =
  | { type: "BaseCampPitched"; id: string; altitude: number }
  | { type: "BaseCampStruck"; at: string };

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const baseCampDecider: Decider<BaseCampCommand, BaseCampEvent, BaseCampState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "pitch":
        if (state.status !== "none") throw new Error("EXISTS");
        return [{ type: "BaseCampPitched", id: command.id, altitude: command.altitude }];
      case "strike":
        if (state.status !== "pitched") throw new Error("NOT_PITCHED");
        return [{ type: "BaseCampStruck", at: command.at }];
      default: {
        const _never: never = command;
        throw new Error("UNKNOWN_COMMAND");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "BaseCampPitched":
        return { status: "pitched", id: event.id, altitude: event.altitude };
      case "BaseCampStruck":
        return { status: "none" };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};

export interface AuditEntry<E> {
  readonly event: E;
  readonly recordedAt: string;
}

export function decideWithAudit<C, E, S>(
  decider: Decider<C, E, S>,
  command: C,
  state: S,
  now: string,
): { events: E[]; log: AuditEntry<E>[] } {
  const events = decider.decide(command, state);
  const log = events.map((event) => ({ event, recordedAt: now }));
  return { events, log };
}
